export type ParsedSellInstruction<
  TProgram extends string = typeof LAUNCHPAD_PROGRAM_ADDRESS,
  TAccountMetas extends readonly AccountMeta[] = readonly AccountMeta[],
> = {
  programAddress: Address<TProgram>;
  accounts: {
    seller: TAccountMetas[0];
    mint: TAccountMetas[1];
    curve: TAccountMetas[2];
    curveTokenVault: TAccountMetas[3];
    sellerTokenAccount: TAccountMetas[4];
    creator: TAccountMetas[5];
    treasury: TAccountMetas[6];
    tokenProgram: TAccountMetas[7];
  };
  data: SellInstructionData;
};

export function parseSellInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedSellInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 8) {
    // TODO: Coded error.
    throw new Error("Not enough accounts");
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      seller: getNextAccount(),
      mint: getNextAccount(),
      curve: getNextAccount(),
      curveTokenVault: getNextAccount(),
      sellerTokenAccount: getNextAccount(),
      creator: getNextAccount(),
      treasury: getNextAccount(),
      tokenProgram: getNextAccount(),
    },
    data: getSellInstructionDataDecoder().decode(instruction.data),
  };
}
